class Solution {
public:
int countPairs(int n, int m, std::vector<int>& nums) {
	int count = 0;
	int pre = 0;
	for (int i = 0; i < n; ++ i) {
		pre ^= nums[i];
	}
	for (int i = 0; i < n; ++ i) {
		if (pre ^ nums[i] == m) {
			count ++;
		}
	}
	return count;
}
};

int main() {
	Solution solution;
	int n, m;
	std::cin >> n >> m;
	std::vector<int> nums(n);
	for (int i = 0; i < n; ++ i) {
		std::cin >> nums[i];
	}
	std::cout << solution.countPairs(n, m, nums) << '\n';
	return 0;
}
